import re

def a1_to_rc(ref: str) -> tuple:
    if not ref:
        raise ValueError("Empty reference")
    match = re.fullmatch(r'([A-Za-z]+)([0-9]+)', ref)
    if not match:
        raise ValueError(f"Invalid cell reference: {ref!r}")
    col_str = match.group(1).upper()
    row_str = match.group(2)
    row = int(row_str)
    if row < 1:
        raise ValueError(f"Row must be >= 1, got {row_str!r}")
    col = 0
    for ch in col_str:
        col = col * 26 + (ord(ch) - ord('A') + 1)
    return (row, col)


def expand_range(rng: str) -> list:
    def col_to_letters(col: int) -> str:
        result = ''
        while col > 0:
            col, rem = divmod(col - 1, 26)
            result = chr(ord('A') + rem) + result
        return result

    if ':' not in rng:
        # Single cell — validate and return
        a1_to_rc(rng)  # raises ValueError if invalid
        m = re.fullmatch(r'([A-Za-z]+)([0-9]+)', rng)
        normalized = m.group(1).upper() + m.group(2)
        return [normalized]

    parts = rng.split(':')
    if len(parts) != 2:
        raise ValueError(f"Invalid range: {rng!r}")

    start, end = parts[0].strip(), parts[1].strip()
    r1, c1 = a1_to_rc(start)
    r2, c2 = a1_to_rc(end)

    if r1 > r2 or c1 > c2:
        raise ValueError(
            f"Start cell must be the top-left corner of the range "
            f"(got {start!r}:{end!r})"
        )

    result = []
    for row in range(r1, r2 + 1):
        for col in range(c1, c2 + 1):
            result.append(col_to_letters(col) + str(row))
    return result

